import{c as e,S as d,j as a,m as o}from"./chunks/framework.DvQr6YbT.js";const p=JSON.parse('{"title":"参考","description":"","frontmatter":{},"headers":[],"relativePath":"zh/reference/index.md","filePath":"zh/reference/index.md","lastUpdated":1783505267000}'),r={name:"zh/reference/index.md"};function l(s,t,i,n,c,h){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to “参考”">​</a></h1><p>本页列出 Knowlery 使用的文件、命令、skills 和安全边界。</p><h2 id="插件元数据" tabindex="-1">插件元数据 <a class="header-anchor" href="#插件元数据" aria-label="Permalink to “插件元数据”">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>当前值</th></tr></thead><tbody><tr><td>Plugin ID</td><td><code>knowlery</code></td></tr><tr><td>Minimum Obsidian app version</td><td><code>1.12.2</code></td></tr><tr><td>Desktop-only manifest flag</td><td><code>true</code></td></tr><tr><td>Main bundle</td><td><code>main.js</code></td></tr><tr><td>Stylesheet</td><td><code>styles.css</code></td></tr></tbody></table><h2 id="dashboard-和-settings-surfaces" tabindex="-1">Dashboard 和 Settings Surfaces <a class="header-anchor" href="#dashboard-和-settings-surfaces" aria-label="Permalink to “Dashboard 和 Settings Surfaces”">​</a></h2><table tabindex="0"><thead><tr><th>Surface</th><th>用途</th></tr></thead><tbody><tr><td>Dashboard home</td><td>Today&#39;s move、Suggested moves、Knowledge health、This note、Recent activity、This week 和 Bundles</td></tr><tr><td>Share knowledge bundle</td><td>Seed 选择、graph-closure review、risk scan 和 bundle 导出</td></tr><tr><td>Install knowledge bundle</td><td>Manifest 和 conformance 预览、安装和已安装 bundle 列表</td></tr><tr><td>Move drill-ins</td><td>完整 suggested-move 列表和单个 move prompt</td></tr><tr><td>Activity drill-in</td><td>完整 recent activity 列表</td></tr><tr><td>Freshness Review</td><td>request 准备、result 导入、suggestion decisions、apply 和 undo</td></tr><tr><td>Settings: Diagnostics</td><td>Vault health、content stats、configuration integrity 和 diagnosis</td></tr><tr><td>Settings: Rules &amp; schema</td><td>Agent rules、schema shortcuts 和 config maintenance</td></tr><tr><td>Settings: Skills</td><td>Built-in、registry、custom 和 disabled skill 管理</td></tr></tbody></table><h2 id="创建的文件和文件夹" tabindex="-1">创建的文件和文件夹 <a class="header-anchor" href="#创建的文件和文件夹" aria-label="Permalink to “创建的文件和文件夹”">​</a></h2><table tabindex="0"><thead><tr><th>路径</th><th>Setup 创建</th><th>说明</th></tr></thead><tbody><tr><td><code>KNOWLEDGE.md</code></td><td>是</td><td>Vault 操作指南</td></tr><tr><td><code>SCHEMA.md</code></td><td>是</td><td>知识分类与页面约定</td></tr><tr><td><code>INDEX.base</code></td><td>是</td><td>Bases index</td></tr><tr><td><code>entities/</code></td><td>是</td><td>Agent-maintained entity pages</td></tr><tr><td><code>concepts/</code></td><td>是</td><td>Agent-maintained concept pages</td></tr><tr><td><code>comparisons/</code></td><td>是</td><td>Agent-maintained comparison pages</td></tr><tr><td><code>queries/</code></td><td>是</td><td>Agent-maintained research threads</td></tr><tr><td><code>.knowlery/manifest.json</code></td><td>是</td><td>Setup state</td></tr><tr><td><code>.agents/skills/</code></td><td>是</td><td>Canonical skills</td></tr><tr><td><code>.agents/rules/</code></td><td>OpenCode path</td><td>OpenCode rules</td></tr><tr><td><code>.claude/skills/</code></td><td>是</td><td>为 Claude Code 镜像的内置 skills</td></tr><tr><td><code>.claude/CLAUDE.md</code></td><td>Claude Code path</td><td>Claude instructions</td></tr><tr><td><code>.claude/rules/</code></td><td>Claude Code path</td><td>Claude Code rules</td></tr><tr><td><code>opencode.json</code></td><td>OpenCode path</td><td>OpenCode config</td></tr><tr><td><code>skills-lock.json</code></td><td>是</td><td>Skill lock state</td></tr><tr><td><code>.knowlery/activity/</code></td><td>Activity logging</td><td>私有 activity receipts</td></tr><tr><td><code>.knowlery/reports/</code></td><td>Weekly summary</td><td>本地 HTML report 输出</td></tr><tr><td><code>.knowlery/requests/</code></td><td>Daily polish</td><td>Daily review requests</td></tr><tr><td><code>.knowlery/reviews/</code></td><td>Daily polish</td><td>Daily review results</td></tr><tr><td><code>.knowlery/freshness/</code></td><td>Freshness Review</td><td>Request、result、log、queue 和 sidecar 文件</td></tr><tr><td><code>.knowlery/exports/</code></td><td>Share knowledge bundle</td><td>编译后的 bundle 输出（可选打成 zip）</td></tr><tr><td><code>.knowlery/export-scope.json</code></td><td>Share knowledge bundle</td><td>按主题保存的 review scope</td></tr><tr><td><code>Library/&lt;bundle-id&gt;/</code></td><td>Install knowledge bundle</td><td>已安装 bundle 的内容</td></tr><tr><td><code>.knowlery/bundles.json</code></td><td>Install knowledge bundle</td><td>已安装 bundle 的注册表</td></tr></tbody></table><h2 id="built-in-skills" tabindex="-1">Built-In Skills <a class="header-anchor" href="#built-in-skills" aria-label="Permalink to “Built-In Skills”">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Kind</th><th>用途</th></tr></thead><tbody><tr><td><code>cook</code></td><td>knowledge</td><td>将笔记整理成知识页面并同步 <code>SCHEMA.md</code> taxonomy</td></tr><tr><td><code>ask</code></td><td>knowledge</td><td>从 vault 内容回答问题</td></tr><tr><td><code>explore</code></td><td>knowledge</td><td>追踪想法时间线和连接</td></tr><tr><td><code>challenge</code></td><td>knowledge</td><td>压力测试信念和 drift</td></tr><tr><td><code>ideas</code></td><td>knowledge</td><td>从 vault 内容生成想法</td></tr><tr><td><code>audit</code></td><td>knowledge</td><td>扫描 agent 维护目录中的结构健康问题</td></tr><tr><td><code>organize</code></td><td>knowledge</td><td>建议结构改进</td></tr><tr><td><code>obsidian-cli</code></td><td>tooling</td><td>使用 Obsidian CLI patterns</td></tr><tr><td><code>obsidian-markdown</code></td><td>tooling</td><td>编写 Obsidian markdown</td></tr><tr><td><code>obsidian-bases</code></td><td>tooling</td><td>处理 Bases files</td></tr><tr><td><code>json-canvas</code></td><td>tooling</td><td>处理 JSON Canvas</td></tr><tr><td><code>defuddle</code></td><td>tooling</td><td>从网页提取干净 markdown</td></tr><tr><td><code>vault-conventions</code></td><td>tooling</td><td>执行 vault naming conventions</td></tr><tr><td><code>knowlery-cli</code></td><td>tooling</td><td>用独立的 <code>knowlery</code> CLI 操作知识库</td></tr></tbody></table><h2 id="settings-sections" tabindex="-1">Settings Sections <a class="header-anchor" href="#settings-sections" aria-label="Permalink to “Settings Sections”">​</a></h2><table tabindex="0"><thead><tr><th>Section</th><th>控制内容</th></tr></thead><tbody><tr><td>General</td><td>知识库名称和 Node.js 路径</td></tr><tr><td>Platform</td><td>Claude Code / OpenCode 切换</td></tr><tr><td>Activity</td><td>Activity logging 和 activity ledger rule</td></tr><tr><td>Maintenance</td><td>重新生成 agent config 和重新初始化 vault</td></tr></tbody></table><h2 id="默认-rule-templates" tabindex="-1">默认 Rule Templates <a class="header-anchor" href="#默认-rule-templates" aria-label="Permalink to “默认 Rule Templates”">​</a></h2><p>Knowlery 包含这些默认 rule templates：</p><table tabindex="0"><thead><tr><th>Rule</th><th>用途</th></tr></thead><tbody><tr><td>Citation required</td><td>要求 vault 回答使用 wikilink citations</td></tr><tr><td>Language preference</td><td>匹配用户语言</td></tr><tr><td>Domain context</td><td>描述 vault 的领域</td></tr></tbody></table><h2 id="obsidian-中注册的命令" tabindex="-1">Obsidian 中注册的命令 <a class="header-anchor" href="#obsidian-中注册的命令" aria-label="Permalink to “Obsidian 中注册的命令”">​</a></h2><p>Knowlery 会注册 command palette actions，用于打开 dashboard、初始化 vault、运行诊断、添加 reflection、分享 knowledge bundle、安装 knowledge bundle 和切换平台。</p><p>具体 label 可能随 UI 演进，但命令面主要围绕 review、setup、diagnosis 和 platform migration。</p><h2 id="activity-ledger" tabindex="-1">Activity Ledger <a class="header-anchor" href="#activity-ledger" aria-label="Permalink to “Activity Ledger”">​</a></h2><p>Activity receipts 存在于 <code>.knowlery/activity/YYYY-MM-DD.jsonl</code>。</p><p>它们是私有摘要，不是普通 knowledge pages。settings 中的 activity toggle 可以通过写入 <code>.knowlery/activity-disabled</code> 来关闭记录。</p><h2 id="weekly-summary-and-daily-review" tabindex="-1">Weekly Summary and Daily Review <a class="header-anchor" href="#weekly-summary-and-daily-review" aria-label="Permalink to “Weekly Summary and Daily Review”">​</a></h2><p>Weekly summary 会把 HTML 输出写到：</p><ul><li><code>.knowlery/reports/latest.html</code></li><li><code>.knowlery/reports/weekly/&lt;week-label&gt;.html</code></li></ul><p>Daily review polish 使用：</p><ul><li><code>.knowlery/requests/daily-review-YYYY-MM-DD.json</code></li><li><code>.knowlery/reviews/daily-review-YYYY-MM-DD.json</code></li></ul><h2 id="freshness-review-files" tabindex="-1">Freshness Review Files <a class="header-anchor" href="#freshness-review-files" aria-label="Permalink to “Freshness Review Files”">​</a></h2><p>Freshness Review 使用：</p><ul><li><code>.knowlery/freshness/requests/freshness-review-&lt;timestamp&gt;.json</code></li><li><code>.knowlery/freshness/results/freshness-review-&lt;timestamp&gt;.json</code></li><li><code>.knowlery/freshness/logs/freshness-review-&lt;timestamp&gt;.jsonl</code></li><li><code>.knowlery/freshness/queue.json</code></li><li><code>.knowlery/freshness/notes/*.json</code></li></ul><p>Candidate pages 会从 <code>entities/</code>、<code>concepts/</code>、<code>comparisons/</code> 和 <code>queries/</code> 收集，并受当前 candidate limit 限制。Suggestions 只能 patch 这些知识页面上的 scalar freshness frontmatter。</p><h2 id="network-use" tabindex="-1">Network Use <a class="header-anchor" href="#network-use" aria-label="Permalink to “Network Use”">​</a></h2><p>Knowlery 不收集 telemetry。</p><p>当你显式使用 skill registry 功能时，Knowlery 可能通过 <code>npx skills ...</code> 访问网络。这个命令可能连接外部 skills tooling 使用的服务。Freshness Review 不会调用 model API；它只准备本地 request files，并导入你单独运行的 agent 写出的 result files。</p><h2 id="local-command-use" tabindex="-1">Local Command Use <a class="header-anchor" href="#local-command-use" aria-label="Permalink to “Local Command Use”">​</a></h2><p>当你显式使用 CLI 相关功能或可选 setup preparation 时，Knowlery 可以运行本地命令。</p><p>示例包括：</p><ul><li><code>claude</code></li><li><code>opencode</code></li><li><code>node</code></li><li><code>npx</code></li><li><code>skills</code></li></ul><p>这些命令会在你的电脑上以你的用户权限运行。</p><h2 id="升级行为" tabindex="-1">升级行为 <a class="header-anchor" href="#升级行为" aria-label="Permalink to “升级行为”">​</a></h2><p>当插件版本变化时，Knowlery 会刷新 <code>.agents/skills/</code> 和 <code>.claude/skills/</code> 里的 bundled skills，通过插入缺失的 anchor sections 来迁移 <code>SCHEMA.md</code>，并在有已安装 bundles 时刷新 <code>KNOWLEDGE.md</code> 中的 installed-bundles 指引块。</p><p>在 v0.5.0 中，knowledge bundle 的分享与安装上线：dashboard 的 Bundles 区块、<code>Library/</code> 文件夹和 <code>.knowlery/bundles.json</code> 是新增的表面。在 v0.4.0 中，dashboard maintenance 已移到 Obsidian settings：diagnostics、rules/schema shortcuts 和 Skills library 不再是单独的 dashboard tabs。</p><p>custom 和 forked skills 会被保留。被禁用的 built-in skills 会继续保持禁用状态，即使磁盘上的 bundled copy 已刷新。</p><h2 id="删除行为" tabindex="-1">删除行为 <a class="header-anchor" href="#删除行为" aria-label="Permalink to “删除行为”">​</a></h2><p>当你在 UI 中使用 delete 或 disable actions 时，Knowlery 可能删除 skill 或 rule 文件。</p><p>Setup 不应该删除普通用户笔记。不过，对于重要 vault，仍然建议先测试，并使用版本控制或备份。</p>',45)])])}const b=e(r,[["render",l]]);export{p as __pageData,b as default};
